#include <iostream>
#include <vector>
#include <limits>

using namespace std;

class Solution {
public:
int minSubArrayLen(int k, const vector<int>& nums) {
    int res = numeric_limits<int>::max();
    for (int i = 0; i < nums.size(); ++i) {
        int sum = 0;
        for (int j = i; j < nums.size(); ++j) {
            sum += nums[j];
            if (sum >= k) res = min(res, j - i + 1);
        }
    }
    return res == numeric_limits<int>::max() ? 0 : res;
}
};

tmain() {
    int k = 7;
    vector<int> nums = {2, 3, 1, 2, 4, 3};
    Solution s;
    cout << s.minSubArrayLen(k, nums) << endl;
}
